var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그럼 여러분! 오래 기다리셨죠?","JPN":"みなさま！　大変お待たせしました！","ENG":"Now, everyone, thank you for your patience.","TWN":"讓大家久等了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"지금 아카데미 운동회는 수많은 드론을 통해 스타디움의 전광판에 실시간으로 중계 중!","JPN":"只今アカデミー運動会は複数のドローンでスタジアムの電光掲示板にリアルタイムで中継中！","ENG":"The Academy's Field Day is being broadcast on the stadium big screen in real time through numerous drones.","TWN":"現在學院運動會正通過大量無人機在體育場電子螢幕上即時轉播！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"이제 곧 드디어 마지막 경기가 시작됩니다!","JPN":"いよいよ最後の試合が始まります！","ENG":"Soon, the last game will begin.","TWN":"接下來馬上就要開始最後一場比賽了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그럼 어떤 선수들이 상위권에 올랐는지 소개해 드릴게요!","JPN":"それでは、どの選手が上位に上がってきたのか紹介します！","ENG":"Let me introduce you to the top players of the day.","TWN":"有哪些選手成功晉級了呢？下面由我來為大家介紹一下！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"<color=#ffd34c>먼저 압도적인 점수차로 1등을 차지한! 청팀의 서윤 선수!</color>","JPN":"<color=#ffd34c>まずは圧倒的な点差で1位となっている、青組のアオイ選手！</color>","ENG":"<color=#ffd34c>First, she's got an overwhelming lead over the second place competitor. Seo Yoon of the Blue Team!</color>","TWN":"<color=#ffd34c>首先以壓倒性的分數優勢排在第一名的是！藍隊的徐芸選手！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"<color=#ffd34c>3등은 홍팀의 나이엘 선수!</color>","JPN":"<color=#ffd34c>3位は赤組のナイエル選手！</color>","ENG":"<color=#ffd34c>Third place goes to Naielle Bluesteel of the Red Team!</color>","TWN":"<color=#ffd34c>第三名是紅隊的奈爾選手！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"<color=#ffd34c>4등은 청팀의 케이시 선수!</color>","JPN":"<color=#ffd34c>4位は青組のケイシー選手！</color>","ENG":"<color=#ffd34c>The fourth place goes to Kaci, of the Blue Team!</color>","TWN":"<color=#ffd34c>第四名是藍隊的卡西選手！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"<color=#ffd34c>그리고 아슬아슬한 점수차로 5등을 차지한!</color>","JPN":"<color=#ffd34c>そしてギリギリの点差で5位になった！</color>","ENG":"<color=#ffd34c>And fifth, by a hair's breadth!</color>","TWN":"<color=#ffd34c>以及以細微的分差位列第五名的！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"<color=#ffd34c>홍팀의 미카 선수입니다!</color>","JPN":"<color=#ffd34c>赤組のミカ選手です！</color>","ENG":"<color=#ffd34c>Mika of the Red Team!</color>","TWN":"<color=#ffd34c>紅隊的米卡選手！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"모, 몸이 안 좋아...... 속도 울렁거리는데 근육통까지......","JPN":"き、気持ち悪い……胃がムカムカするし筋肉痛まで……","ENG":"I-I don't feel good... I'm nauseous and aching all over...","TWN":"感，感覺身體狀況不太好……噁心反胃，肌肉也疼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이렇게 부작용이 심해서야......","JPN":"ここまで副作用がひどいなんて……","ENG":"If it causes so many adverse effects...","TWN":"沒想到副作用這麼嚴重……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"역시 최면 마술은 아직 미완성인가 보네. 함부로 쓰면 안 되겠어......","JPN":"やっぱり催眠術はまだ未完成だわ。安易に使うのはやめよう……","ENG":"My hypnosis magic is definitely not complete, just yet. I'd better not use it carelessly.","TWN":"催眠魔術還沒有完成，果然不能隨便用啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"기다려 주신 마지막 경기는......","JPN":"大変お待たせしました。最後の試合は……","ENG":"Thank you for waiting for the last game, which is...","TWN":"大家期待已久的最後一場比賽是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"바로 보물 찾기!","JPN":"お宝探し！","ENG":"a treasure hunt!","TWN":"尋寶！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L28_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"보시다시피 출발선 앞에는 거대한 숲이 자리잡고 있는데요......","JPN":"ご覧のとおり、スタートラインの前には巨大な森があります。","ENG":"As you can see, a massive forest stands in front of the starting line.","TWN":"如大家所見，起跑線前面有一大片樹林……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"이 숲의 끝을 빠져 나가면 그곳에 우승상품인 소원구슬이 놓여 있습니다.","JPN":"この森をくぐり抜けると、そこに優勝賞品の願い玉があります。","ENG":"At the other end of this forest lies the big prize, the Wishing Ball.","TWN":"走出樹林就能看到放在那裡的優勝獎品——許願珠。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그 소원구슬을 손에 넣은 자! 그 사람이 바로 이번 운동회의 우승자입니다!","JPN":"その願い玉を手に入れた者！　その人がこの運動会の優勝者になります！","ENG":"Whoever gets ahold of the Wishing Ball will be the Field Day winner!","TWN":"拿到那顆許願珠的人！就是這次運動會的冠軍！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"자! 그럼!","JPN":"さて！","ENG":"Alright, now!","TWN":"好了！那麼！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"과연 아카데미 운동회 최고의 영광을 차지하는 자......!","JPN":"果たしてアカデミー運動会で頂点に立つ者……！","ENG":"Who will take the highest honor of the Academy's Field Day","TWN":"學院運動會的最高榮耀究竟會花落誰家……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그리고 소원구슬의 주인은 누가 될 것인가!","JPN":"そして願い玉を手に入れる者は誰になるのでしょうか？","ENG":"and become the owner of the Wishing Ball?","TWN":"許願珠將落入何人之手！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"두구두구! 두근두근!","JPN":"ドキドキ！　ワクワク！","ENG":"Drum roll, please!","TWN":"噔噔噔噔！讓我們拭目以待吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"회장...... 내가 중간에 자다가 깨서 이해가 잘 안 되는데......","JPN":"会長……途中寝ていたから理解できてないけど……","ENG":"Yen... I'm probably not getting this because I fell asleep midway,","TWN":"會長……我中途睡著了，嗯，不是很理解……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"보물 찾기로 소원구슬의 주인을 결정할 거면 경기는 왜 한 거야?","JPN":"お宝探しで願い玉の持ち主を決めるなら、わざわざ試合をする必要なくない？","ENG":"but if you were just going to give the Wishing Ball to whoever finds it, why did you even bother with all the other games?","TWN":"如果要通過尋寶決定許願珠的主人，那為什麼還要比賽啊？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"다들 참가할 수 있으면 점수, 의미 없지 않아......?","JPN":"みんな参加できるなら、点数は意味ないんじゃない……？","ENG":"If anyone can find the Wishing Ball, there's no need for the points, is there?","TWN":"大家都參加的話，分數就沒意義了，不是嗎……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"결과보다 과정이 중요하다는 사실을 학생들에게 가르쳐 주고 싶었을 뿐이에요.","JPN":"結果より過程が重要だということを生徒たちに教えたかっただけです。","ENG":"I wanted to teach our students that the process is more important than the result.","TWN":"我就是想教會學生們過程比結果更重要的這個道理。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뜻은 좋은데 말이지......","JPN":"意図はいいかもしれないけど……","ENG":"I get what you mean, but...","TWN":"這個初衷是不錯……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"막판 뒤집기로 우승 상품을 주면 과정은 상관없어지는 거 아닐까......?","JPN":"終盤の逆転で優勝が決まるなら、過程は関係なくなるんじゃない……？","ENG":"By giving away the winning prize like this, you're actually nullifying the process.","TWN":"可是如果通過逆襲拿走優勝獎品，那過程豈不就變得沒有意義了……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오늘 이 섬에 모인 학생들은 모두 자기가 할 수 있는 선에서 최선을 다했어요.","JPN":"今日この島に集まった生徒たちは、みなさん自分ができる範囲で最善を尽くしました。","ENG":"Every student who came to this island today has done the best they can do,","TWN":"今天聚到這個島上的學生全都在自己力所能及的範圍內盡了最大努力。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그건 결국 자신이 가진 소중한 소원을 이루기 위해서였죠.","JPN":"それは自分の大切な願いを叶えるためでした。","ENG":"because they want to have their most cherished wish come true.","TWN":"那都是為了最終實現自己的寶貴願望。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학교는 우열을 정해 주는 곳이 아니라, 희망을 주는 곳이어야 해요.","JPN":"学校は優劣を決める場所ではなく、希望を与える場所でなければなりません。","ENG":"School shouldn't just be where they're graded by their performance; it also should be where they find hope.","TWN":"學校應該是給予希望的地方，而不是決定優劣的地方。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 저는 남들보다 조금 못났더라도, 약간 뒤처지더라도 소원을 이룰 기회가 있다는 사실을 가르쳐 주고 싶어요.","JPN":"だから私は、他の人より少し足りなくても、\\n少し遅れていても、願いを叶える機会があるという事実を教えてあげたいのです。","ENG":"I want them to know even if they're not as good as others, they still can have an equal chance at making their wish come true.","TWN":"所以，我想教會學生一個道理，那就是哪怕我比別人稍微差一點，稍微落後一些，也有機會夢想成真。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐음...... 시엘이 가만 안 있을 것 같긴 한데......","JPN":"うーん…シエルに怒られる気がするけど……","ENG":"Hmm... I don't think Ciel would be happy about this...","TWN":"哼嗯……我感覺西艾爾是不會放過你的……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐어, 회장이 그렇다면야. 난 괜찮아.","JPN":"まあ、会長がそう言うなら私も大丈夫。","ENG":"Well, if that's what you really want, I'm okay.","TWN":"不過，既然是會長的決定，我沒關係。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"고마워요, 이디스.","JPN":"ありがとうございます、イーディス。","ENG":"Thank you, Edith.","TWN":"謝謝你，伊蒂絲。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 전 결승전이 잘 진행되는지 확인하러 가 봐야겠습니다.","JPN":"では、決勝戦が順調に進んでいるか確認しに行きます。","ENG":"Now, I'll have to go check how everyone is doing in the final game.","TWN":"那我去看看決賽進行得如何了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스도 따라오세요.","JPN":"イーディスも一緒に来てください。","ENG":"Edith, you should come with me.","TWN":"伊蒂絲你也跟我來。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"나, 나도? 나 아직 낮잠 덜 잤는데......?","JPN":"わ、私も？　ま、まだ昼寝が足りないのに……！","ENG":"M-me? But I'm not done napping yet...","TWN":"我，我也？我午睡還沒睡夠呢……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"자! 최후의 최후! 이제 영광의 고지가 코앞입니다!","JPN":"さあ！　最後の最後！　栄光の扉は目の前にある！","ENG":"Now, we're so close to the end! The hill of glory is right before our eyes!","TWN":"好啦！最後的最後！榮耀已經近在眼前了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"눈앞에 숨겨진 우승상품의 주인은 누가 될 것인가!","JPN":"願い玉を手に入れる者は誰になるのでしょうか？","ENG":"Who's going to find the winning prize that's hidden under our noses?","TWN":"藏在眼前的冠軍獎品將落入何人之手！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그럼 다들 마지막까지 최선을 다해 주세요!","JPN":"最後まで最善を尽くしてください！","ENG":"Everyone, please do your best until the end!","TWN":"大家全力以赴地拼搏到最後吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"경기, 시작!","JPN":"試合、スタート！","ENG":"Let's start the game!","TWN":"比賽，開始！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};